import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"Quickstart","description":"","frontmatter":{},"headers":[],"relativePath":"start/quickstart.md","filePath":"start/quickstart.md","lastUpdated":null}'),l={name:"start/quickstart.md"};function h(n,e,o,p,r,d){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="quickstart" tabindex="-1">Quickstart <a class="header-anchor" href="#quickstart" aria-label="Permalink to &quot;Quickstart&quot;">​</a></h1><p>The fastest way to see Autofac working is the tokenless quickstart. It runs the API and web UI with a deterministic mock model provider, so you do not need API keys, GitHub credentials, or external accounts.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Docker</li><li>Docker Compose</li></ul><h2 id="start-the-stack" tabindex="-1">Start the stack <a class="header-anchor" href="#start-the-stack" aria-label="Permalink to &quot;Start the stack&quot;">​</a></h2><p>From the repository root:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker/docker-compose.quickstart.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span></span></code></pre></div><p>Wait for the API and web UI containers to start, then open:</p><table tabindex="0"><thead><tr><th>URL</th><th>Purpose</th></tr></thead><tbody><tr><td><code>http://localhost:3002</code></td><td>Autofac web UI</td></tr><tr><td><code>http://localhost:8081/api/health/live</code></td><td>API liveness probe</td></tr></tbody></table><p>You can check the API from a terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8081/api/health/live</span></span></code></pre></div><p>Expected response:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;live&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="run-the-sample-workflow" tabindex="-1">Run the sample workflow <a class="header-anchor" href="#run-the-sample-workflow" aria-label="Permalink to &quot;Run the sample workflow&quot;">​</a></h2><ol><li>Open <code>http://localhost:3002</code>.</li><li>Go to the Runs page.</li><li>Click <strong>Run sample workflow</strong>.</li></ol><p>The seeded workflow is a small governed SDLC slice:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Draft Implementation Note -&gt; Review Sample Output -&gt; Done</span></span></code></pre></div><p>The agent step uses the mock provider. It completes without model credentials and without token cost.</p><h2 id="approve-the-review-gate" tabindex="-1">Approve the review gate <a class="header-anchor" href="#approve-the-review-gate" aria-label="Permalink to &quot;Approve the review gate&quot;">​</a></h2><p>When the run reaches the review step, it pauses at a human approval task.</p><ol><li>Open the run detail page.</li><li>Review the agent output and policy rationale.</li><li>Click <strong>Approve</strong>.</li></ol><p>After the approval decision, the run should move to <code>completed</code>.</p><h2 id="inspect-the-evidence" tabindex="-1">Inspect the evidence <a class="header-anchor" href="#inspect-the-evidence" aria-label="Permalink to &quot;Inspect the evidence&quot;">​</a></h2><p>Every run can expose an evidence pack through the API:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8081/api/runs/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">run-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/evidence-pack</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer &lt;dev-token&gt;&quot;</span></span></code></pre></div><p>The quickstart UI handles the easiest path. Use the API path when you are validating automation or collecting evidence in CI.</p><h2 id="stop-the-stack" tabindex="-1">Stop the stack <a class="header-anchor" href="#stop-the-stack" aria-label="Permalink to &quot;Stop the stack&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker/docker-compose.quickstart.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> down</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><p>The <code>-v</code> flag removes the quickstart database volume so the next run starts from a clean seeded state.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li>Learn how runs progress: <a href="/manual/runs.html">Runs</a></li><li>Learn approvals and evidence: <a href="/manual/approvals-evidence.html">Approvals And Evidence</a></li><li>Configure a real model provider: <a href="/manual/model-providers.html">Model Providers</a></li><li>Start runs from GitHub issues: <a href="/manual/github-issue-trigger.html">GitHub Issue Trigger</a></li><li>Harden deployment settings: <a href="/admin/deployment.html">Deployment</a></li></ul>`,31)])])}const u=t(l,[["render",h]]);export{k as __pageData,u as default};
